const planta = {
  nombre: "Tomatera",
  especie: "Solanum",
  diasSinAgua: 2,
  enFlor: false
};

// Leer una propiedad con el punto
console.log(planta.nombre);      // "Tomatera"

// Cambiar una propiedad
planta.diasSinAgua = 0;
console.log(planta.diasSinAgua); // 0

const huerto = [
  { nombre: "Tomatera", diasSinAgua: 2 },
  { nombre: "Albahaca", diasSinAgua: 5 },
  { nombre: "Menta",    diasSinAgua: 0 }
];

for (const planta of huerto) {
  console.log(planta.nombre + ": " + planta.diasSinAgua + " días");
}
// Tomatera: 2 días
// Albahaca: 5 días
// Menta: 0 días

const planta = {
  nombre: "Tomatera",
  diasSinAgua: 4,
  regar() {
    this.diasSinAgua = 0;   // this = esta planta
  }
};

planta.regar();
console.log(planta.diasSinAgua); // 0

class Planta {
  constructor(nombre, especie) {
    this.nombre = nombre;       // datos iniciales
    this.especie = especie;
    this.diasSinAgua = 0;
  }
  regar() {
    this.diasSinAgua = 0;
  }
  necesitaAgua() {
    return this.diasSinAgua > 3;
  }
}

// Fabricar objetos concretos con new
const tomatera = new Planta("Tomatera", "Solanum");
const menta = new Planta("Menta", "Mentha");

console.log(tomatera.nombre);       // "Tomatera"
console.log(menta.necesitaAgua());  // false

class Coche {
  constructor(matricula, averia) {
    this.matricula = matricula;
    this.averia = averia;
    this.reparado = false;
  }
  marcarReparado() {
    this.reparado = true;
  }
}

class Equipo {
  constructor(nombre) {
    this.nombre = nombre;
    this.puntos = 0;
  }
  ganar() { this.puntos += 3; }
  empatar() { this.puntos += 1; }
}

const tigres = new Equipo("Los Tigres");
tigres.ganar();
console.log(tigres.puntos); // 3

