    this.diasSinAgua = 0;
  }
  necesitaAgua() { return this.diasSinAgua > 3; }
}

const huerto = [
  new Planta("Tomatera"),
  new Planta("Albahaca"),
  new Planta("Menta")
];

huerto[1].diasSinAgua = 5;

for (const planta of huerto) {
  if (planta.necesitaAgua()) {
    console.log(planta.nombre + " necesita agua");
  }
}
// Albahaca necesita agua

